import { describe, it, expect, afterEach } from 'vitest';
import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import { detectPackageManager } from '../src/detect';

function makeTempDir(): string {
    return fs.mkdtempSync(path.join(os.tmpdir(), 'bi-test-'));
}

function cleanup(dir: string): void {
    fs.rmSync(dir, { recursive: true, force: true });
}

describe('detectPackageManager', () => {
    let tempDir: string;

    afterEach(() => {
        if (tempDir) cleanup(tempDir);
    });

    it('should detect npm from package-lock.json', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'package-lock.json'), '{}');
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('npm');
        expect(result.reason).toBe('lockfile');
        expect(result.lockfile).toBe('package-lock.json');
    });

    it('should detect yarn from yarn.lock', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'yarn.lock'), '');
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('yarn');
        expect(result.reason).toBe('lockfile');
        expect(result.lockfile).toBe('yarn.lock');
    });

    it('should detect pnpm from pnpm-lock.yaml', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'pnpm-lock.yaml'), '');
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('pnpm');
        expect(result.reason).toBe('lockfile');
        expect(result.lockfile).toBe('pnpm-lock.yaml');
    });

    it('should detect bun from bun.lockb', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'bun.lockb'), '');
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('bun');
        expect(result.reason).toBe('lockfile');
        expect(result.lockfile).toBe('bun.lockb');
    });

    it('should detect bun from bun.lock', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'bun.lock'), '');
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('bun');
        expect(result.reason).toBe('lockfile');
    });

    it('should prefer lockfile over packageManager field', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'yarn.lock'), '');
        fs.writeFileSync(path.join(tempDir, 'package.json'), JSON.stringify({ packageManager: 'pnpm@8.0.0' }));
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('yarn');
        expect(result.reason).toBe('lockfile');
    });

    it('should use packageManager field when no lockfile exists', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'package.json'), JSON.stringify({ packageManager: 'pnpm@8.15.0' }));
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('pnpm');
        expect(result.reason).toBe('packageManager-field');
        expect(result.version).toBe('8.15.0');
    });

    it('should parse version from packageManager field', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'package.json'), JSON.stringify({ packageManager: 'yarn@4.1.0' }));
        const result = detectPackageManager(tempDir);
        expect(result.pm).toBe('yarn');
        expect(result.version).toBe('4.1.0');
    });

    it('should return reason=lockfile when detected from lockfile', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'package-lock.json'), '{}');
        const result = detectPackageManager(tempDir);
        expect(result.reason).toBe('lockfile');
    });

    it('should return reason=packageManager-field when detected from field', () => {
        tempDir = makeTempDir();
        fs.writeFileSync(path.join(tempDir, 'package.json'), JSON.stringify({ packageManager: 'bun@1.0.0' }));
        const result = detectPackageManager(tempDir);
        expect(result.reason).toBe('packageManager-field');
    });

    it('should handle empty directory with PATH fallback or default', () => {
        tempDir = makeTempDir();
        const result = detectPackageManager(tempDir);
        // Will either find a PM on PATH or default to npm
        expect(['npm', 'yarn', 'pnpm', 'bun']).toContain(result.pm);
        expect(['path-lookup', 'default']).toContain(result.reason);
    });
});
